const ge8PrelimExam: QuizQuestion[] = [
  { question: "Ethics is the branch of philosophy concerned with:", options: ["Physical laws of the universe", "Systematic study of what is morally right, wrong, good, and evil", "Government policies and legislation", "Biological traits of human beings"], answer: 1, explanation: "Ethics is the philosophical discipline that systematically studies moral principles, values, and human conduct." },
  { question: "Which branch of ethics asks 'What IS morality?'", options: ["Metaethics", "Normative Ethics", "Applied Ethics", "Descriptive Ethics"], answer: 0, explanation: "Metaethics investigates the nature, foundations, and meaning of moral concepts and moral language." },
  { question: "Normative ethics primarily asks:", options: ["What is the biological basis of behavior?", "What SHOULD we do? What makes actions right or wrong?", "What laws does the government impose?", "What is the history of moral beliefs?"], answer: 1, explanation: "Normative ethics seeks to establish standards (norms) for right and wrong action — what we should and should not do." },
  { question: "Applied ethics differs from normative ethics in that it:", options: ["Studies the nature of moral language", "Applies ethical theories to specific real-world situations such as IT ethics", "Develops abstract philosophical systems", "Describes cultural moral practices"], answer: 1, explanation: "Applied ethics takes normative theories and applies them to concrete areas such as medical ethics, environmental ethics, and computer ethics." },
  { question: "Morality, as distinct from ethics, refers to:", options: ["Systematic philosophical study of right and wrong", "The actual beliefs, customs, and practices people hold about right and wrong", "Only laws enacted by governments", "Scientific research on human behavior"], answer: 1, explanation: "Morality refers to the actual moral beliefs, norms, and practices of a person or group; ethics is the philosophical study of those beliefs." },
  { question: "The statement 'You should always keep your promises' is an example of:", options: ["Descriptive ethics", "Normative ethics", "Metaethics", "Natural science"], answer: 1, explanation: "Normative ethics makes prescriptive claims about what one ought to do — such as the duty to keep promises." },
  { question: "Utilitarianism was developed by:", options: ["Immanuel Kant and Aristotle", "Jeremy Bentham and John Stuart Mill", "Thomas Hobbes and John Locke", "Carol Gilligan and Nel Noddings"], answer: 1, explanation: "Utilitarianism was formulated by Jeremy Bentham and refined by John Stuart Mill as a consequentialist moral theory." },
  { question: "The Utilitarian principle holds that the right action is:", options: ["The one that follows the moral law regardless of consequences", "The one that produces the greatest good for the greatest number", "The one chosen by people of good character", "The one based on social agreement"], answer: 1, explanation: "Utilitarianism is consequentialist — it judges an action as right if it maximizes overall happiness or welfare." },
  { question: "Utilitarianism is classified as a:", options: ["Deontological theory", "Consequentialist theory", "Virtue-based theory", "Contractarian theory"], answer: 1, explanation: "Utilitarianism focuses on consequences — the morality of an action is determined by its outcomes." },
  { question: "Kant's moral philosophy is based on:", options: ["Consequences — whether an action produces happiness", "Duty — acting according to moral law regardless of outcomes", "Relationships and empathy", "Social agreements among rational people"], answer: 1, explanation: "Kant's deontology centers on duty and moral law — the rightness of an action depends on whether it conforms to moral duty, not its consequences." },
  { question: "The Categorical Imperative states:", options: ["Act to maximize happiness for the most people", "Act only on principles you could will to become universal laws", "Act as a virtuous person would in this situation", "Act on the basis of social agreement"], answer: 1, explanation: "Kant's Categorical Imperative: 'Act only according to that maxim by which you can at the same time will that it should become a universal law.'" },
  { question: "Kant's Formula of Humanity requires that you:", options: ["Maximize social benefit in your decisions", "Always treat persons as ends in themselves, never merely as means", "Follow customs and traditions of your community", "Act to preserve social harmony"], answer: 1, explanation: "Kant's second formulation: Act in a way that you always treat humanity, both in yourself and others, as an end, never merely as a means." },
  { question: "Which ethical theory focuses on character and virtues rather than rules or consequences?", options: ["Virtue Ethics", "Utilitarianism", "Deontology", "Social Contract Theory"], answer: 0, explanation: "Virtue Ethics, rooted in Aristotle's thought, focuses on developing good character traits (virtues) rather than following rules or calculating consequences." },
  { question: "Aristotle's concept of eudaimonia refers to:", options: ["A type of logical argument", "Human flourishing — living well and doing well", "A legal contract among citizens", "The principle of maximizing pleasure"], answer: 1, explanation: "Eudaimonia (Greek: 'happiness' or 'flourishing') is Aristotle's term for the ultimate goal of human life — living well through the exercise of virtue." },
  { question: "According to Aristotle, moral virtues are developed through:", options: ["Formal lectures and reading only", "Habit and repeated practice", "Divine revelation", "Studying legal codes"], answer: 1, explanation: "Aristotle taught that while intellectual virtues come from teaching, moral virtues are acquired by doing — through habit and practice." },
  { question: "The Ethics of Care was primarily developed by:", options: ["Jeremy Bentham and Mill", "Immanuel Kant and Rousseau", "Carol Gilligan and Nel Noddings", "Thomas Hobbes and Aristotle"], answer: 2, explanation: "The Ethics of Care emerged from feminist moral philosophy, particularly the work of Carol Gilligan (who critiqued Kohlberg's justice-based ethics) and Nel Noddings." },
  { question: "Ethics of Care emphasizes:", options: ["Universal moral rules applicable to everyone equally", "Relationships, empathy, and responsibilities to particular others", "Social contracts among rational individuals", "The consequences of actions for society"], answer: 1, explanation: "Ethics of Care holds that morality is rooted in care, relationships, and responding to particular others' needs — not in abstract universal rules." },
  { question: "Social Contract Theory holds that morality is based on:", options: ["God's commands revealed through scripture", "Agreement among rational individuals who form a society", "The character of virtuous individuals", "The consequences of actions for overall happiness"], answer: 1, explanation: "Social Contract Theory: morality and legitimate government arise from agreements (explicit or implicit) among rational people who establish social cooperation." },
  { question: "Thomas Hobbes described the state of nature (before society) as:", options: ["Peaceful and cooperative", "'Solitary, poor, nasty, brutish, and short'", "A time of perfect virtue", "Governed by divine law"], answer: 1, explanation: "Hobbes argued that without government, life in the state of nature would be a 'war of all against all,' making life 'solitary, poor, nasty, brutish, and short.'" },
  { question: "John Locke's Social Contract Theory argued that government must protect:", options: ["Military power and national expansion", "Life, liberty, and property", "Religious doctrine and tradition", "Cultural homogeneity"], answer: 1, explanation: "Locke maintained that people enter the social contract to protect their natural rights to life, liberty, and property — and government is legitimate only if it does so." },
  { question: "Rousseau's Social Contract Theory emphasized that:", options: ["Monarchs have absolute authority", "Government power derives from the general will of the people", "Moral laws come from nature alone", "Property rights justify inequality"], answer: 1, explanation: "Rousseau argued that legitimate political authority rests on a social contract that expresses the 'general will' of the people." },
  { question: "Natural Law Theory, most associated with St. Thomas Aquinas, holds that moral standards are:", options: ["Decided by majority vote", "Derived from the rational nature of humans", "Created by social agreement", "Purely subjective preferences"], answer: 1, explanation: "Natural Law: moral standards governing human behavior are objectively derived from the rational nature of human beings and are universally accessible to reason." },
  { question: "Computer ethics is a branch of:", options: ["Political science", "Applied ethics", "Metaethics", "Descriptive ethics"], answer: 1, explanation: "Computer ethics is a branch of applied ethics that studies moral issues arising from the development and use of computers and IT." },
  { question: "The Ten Commandments of Computer Ethics were published by:", options: ["The United Nations Technology Division", "Computer Ethics Institute (CEBI) in 1992", "IEEE Computer Society in 2000", "The Philippine Congress in 2012"], answer: 1, explanation: "The Ten Commandments of Computer Ethics were formulated by the Computer Ethics Institute (CEBI) in 1992 as a guide for ethical computer use." },
  { question: "The First Commandment of Computer Ethics states:", options: ["Thou shalt not copy software without paying", "Thou shalt not use a computer to harm other people", "Thou shalt think about social consequences of programs", "Thou shalt not use computers for work"], answer: 1, explanation: "The First Commandment: 'Thou shalt not use a computer to harm other people.' This is the foundational principle of computer ethics." },
  { question: "'Thou shalt not copy or use proprietary software without paying' addresses:", options: ["Environmental sustainability", "Intellectual property and software piracy", "Online bullying", "Network security only"], answer: 1, explanation: "The Sixth Commandment addresses intellectual property — copying proprietary software without authorization is theft of the creator's work." },
  { question: "Proprietary software differs from open-source software in that:", options: ["Proprietary software is always free", "Proprietary software is owned and its source code is not publicly available", "Open-source software can only be used by corporations", "Proprietary software has no restrictions on modification"], answer: 1, explanation: "Proprietary software is owned by a company; users must pay for a license and cannot access, modify, or redistribute the source code." },
  { question: "Open-source software means:", options: ["Software that costs nothing to buy", "Software whose source code is publicly available and can be modified and distributed", "Software created by the government", "Software that runs without an operating system"], answer: 1, explanation: "Open-source software makes its source code freely available — developers can view, modify, and distribute it under open-source licenses." },
  { question: "Freeware is best described as:", options: ["Software with an open-source license", "Software free to use but with source code not available", "Software that requires a subscription", "Software distributed only in the Philippines"], answer: 1, explanation: "Freeware is free to download and use, but unlike open-source, the source code is not available. Users cannot modify the program." },
  { question: "Shareware is:", options: ["Open-source software shared freely", "Software you can try before buying; full features require payment", "Software that must be purchased before using", "A type of cloud computing service"], answer: 1, explanation: "Shareware allows users to try the software for free, but continued use or access to full features requires purchasing a license." },
  { question: "RA 10175 in the Philippines is the:", options: ["Data Privacy Act of 2012", "Cybercrime Prevention Act of 2012", "NSTP Law of 2001", "Electronic Commerce Act of 2000"], answer: 1, explanation: "RA 10175 is the Cybercrime Prevention Act of 2012 — it criminalizes online offenses such as hacking, cybersex, and online libel." },
  { question: "RA 10173 is the:", options: ["Cybercrime Prevention Act", "Data Privacy Act of 2012", "Electronic Commerce Act", "Intellectual Property Code"], answer: 1, explanation: "RA 10173 is the Data Privacy Act of 2012 — it protects personal information collected, stored, and processed by organizations." },
  { question: "Under RA 10175, cybercrime includes:", options: ["Only physical theft of computers", "Unauthorized access, identity theft, cybersex, and online libel", "Only copyright infringement", "Only sending spam emails"], answer: 1, explanation: "RA 10175 covers offenses including illegal access, data interference, cybersex, child pornography, identity theft, cybersquatting, and online libel." },
  { question: "Data privacy is most directly threatened by:", options: ["Using open-source software", "Unauthorized collection, use, or sharing of personal information", "Writing clean code", "Following computer ethics commandments"], answer: 1, explanation: "Data privacy violations involve accessing or using personal data without proper consent or authorization." },
  { question: "Intellectual property in computing includes:", options: ["Only physical devices", "Software code, algorithms, databases, and digital creative works", "Only hardware patents", "Only government documents"], answer: 1, explanation: "Intellectual property in IT includes software, algorithms, databases, digital content, and other intangible creations protected by copyright, patent, and trademark laws." },
  { question: "Which statement is an example of metaethics?", options: ["'You should always be honest.'", "'Many cultures prohibit stealing.'", "'Are moral facts objective or just personal opinions?'", "'Lying is wrong because it reduces overall happiness.'"], answer: 2, explanation: "Metaethics investigates whether moral facts are objective (exist independently) or merely subjective expressions of opinion — a question about the nature of morality itself." },
  { question: "A deontologist would argue that lying to save a life is:", options: ["Acceptable because the consequences are good", "Wrong because lying violates a moral rule regardless of consequences", "Acceptable because most people would agree", "Neither right nor wrong"], answer: 1, explanation: "Deontologists (Kant) hold that the rightness of an action depends on following moral rules (duty), not on its consequences — lying is wrong even if it saves someone." },
  { question: "A utilitarian would argue that lying to save a life is:", options: ["Always wrong because honesty is a duty", "Acceptable if it produces more good than harm overall", "Wrong because it sets a bad example", "Dependent only on who is watching"], answer: 1, explanation: "Utilitarianism evaluates actions by their consequences — lying may be right if it produces the greatest good for the greatest number." },
  { question: "The 'universalizability test' is associated with:", options: ["Aristotle", "Jeremy Bentham", "Immanuel Kant", "Carol Gilligan"], answer: 2, explanation: "Kant's universalizability test (from the Categorical Imperative): 'Can I will that everyone act on this same principle?' — it tests the moral consistency of an action." },
  { question: "Mores are best described as:", options: ["Optional personal habits", "Strong moral norms enforced by social pressure", "Laws passed by the legislature", "Random cultural traditions with no moral weight"], answer: 1, explanation: "Mores are deeply held moral norms and customs enforced by social approval and disapproval — more binding than folkways but less formal than laws." },
  { question: "'Think about the social consequences of the programs you write' appears in which Commandment of Computer Ethics?", options: ["Fourth Commandment", "Seventh Commandment", "Ninth Commandment", "Tenth Commandment"], answer: 2, explanation: "The Ninth Commandment: 'Thou shalt think about the social consequences of the program you are writing or the system you are designing.'" },
  { question: "A professional code of ethics for IT professionals serves to:", options: ["Replace government laws", "Guide professionals' behavior and ensure they act in the public interest", "Prevent innovation", "Make software more expensive"], answer: 1, explanation: "Professional codes of ethics (e.g., ACM, IEEE) guide practitioners to act responsibly, protect the public, and maintain integrity in their work." },
  { question: "Virtue ethics would evaluate an IT professional's decision by asking:", options: ["Does this maximize overall social benefit?", "Does this follow the established rule?", "Would a person of good character make this choice?", "Did most people agree to this decision?"], answer: 2, explanation: "Virtue ethics focuses on character — the right action is what a virtuous person (honest, careful, just) would do in a given situation." },
  { question: "Algorithmic bias in AI raises which ethical concern?", options: ["Physical safety of programmers only", "Fairness — automated systems may discriminate against certain groups", "Energy consumption of data centers", "Only financial costs of AI"], answer: 1, explanation: "Algorithmic bias occurs when AI systems produce unfair or discriminatory outcomes, often reflecting biases in training data — raising justice and fairness concerns." },
  { question: "Digital surveillance raises concerns primarily about:", options: ["Improving user experience", "Privacy and freedom from unwarranted monitoring", "Reducing cybercrime only", "Making software run faster"], answer: 1, explanation: "Digital surveillance — by governments or corporations — threatens privacy and may suppress freedom of expression, movement, and association." },
  { question: "Which ethical theory is most closely associated with the concept of human dignity?", options: ["Kantian Deontology", "Utilitarianism", "Social Contract Theory", "Ethics of Care"], answer: 0, explanation: "Kantian ethics emphasizes human dignity — the Formula of Humanity commands us to treat all persons as ends in themselves, never merely as means, because of their inherent dignity." },
  { question: "The 'Trolley Problem' is a classic case study used in:", options: ["Social Contract Theory", "Applied and normative ethics — highlighting the tension between consequentialism and deontology", "Environmental ethics only", "Computer security"], answer: 1, explanation: "The Trolley Problem illustrates how utilitarianism (sacrifice one to save five) conflicts with deontological ethics (it is wrong to use a person as a means)." },
  { question: "Which commandment directly addresses unauthorized access to others' files?", options: ["First Commandment", "Second Commandment", "Third Commandment", "Fifth Commandment"], answer: 2, explanation: "Third Commandment: 'Thou shalt not snoop around in other people's files.' This directly addresses unauthorized access to private data." },
  { question: "Ethics is different from law in that:", options: ["Ethics has no relevance to human behavior", "Ethics can prohibit behavior that is legally permitted, and require behavior the law does not mandate", "Law always reflects perfect ethics", "Ethics is only for philosophers"], answer: 1, explanation: "Law sets minimum standards enforced by government; ethics can demand more (going beyond the law) or prohibit what is legally allowed (e.g., legal but unethical practices)." },
  { question: "Which philosopher argued that people are naturally free and equal in the state of nature?", options: ["Thomas Hobbes", "John Locke", "Immanuel Kant", "Aristotle"], answer: 1, explanation: "Locke argued that in the state of nature, all people are equal and possess natural rights to life, liberty, and property — unlike Hobbes who saw the state of nature as war." },
  { question: "A person who copies software and distributes it without authorization is violating:", options: ["Only physical property rights", "Intellectual property rights — specifically copyright", "Only data privacy rights", "No rights, since software is digital"], answer: 1, explanation: "Unauthorized copying and distribution of software violates copyright law — software is protected intellectual property." },
];

const nstp2PrelimExam: QuizQuestion[] = [
  { question: "RA 9163 (The NSTP Law) was enacted in:", options: ["1987", "1995", "2001", "2010"], answer: 2, explanation: "Republic Act 9163, the National Service Training Program Act, was signed into law in 2001." },
  { question: "RA 9163 mandates NSTP for:", options: ["Graduate school students only", "All incoming freshmen in tertiary education (public and private schools)", "Senior high school students only", "College faculty members"], answer: 1, explanation: "RA 9163 requires all incoming first-year college students — in both public and private schools — to take the NSTP program." },
  { question: "RA 9163 replaced which previous program?", options: ["Citizens' Army Training (CAT)", "Citizen's Military Training (CMT)", "Barangay Youth Training Program", "National Community Service"], answer: 1, explanation: "RA 9163 replaced the old Citizen's Military Training (CMT) program that was previously mandatory in schools." },
  { question: "How many NSTP components are defined under RA 9163?", options: ["Two", "Three", "Four", "Five"], answer: 1, explanation: "RA 9163 defines three NSTP components: CWTS (Civic Welfare Training Service), ROTC (Reserve Officers' Training Corps), and LTS (Literacy Training Service)." },
  { question: "CWTS stands for:", options: ["Civic Warfare Training Service", "Civic Welfare Training Service", "Community Work and Teaching Service", "Civic Wellness Training System"], answer: 1, explanation: "CWTS = Civic Welfare Training Service — the NSTP component focused on community service and social development." },
  { question: "ROTC stands for:", options: ["Reserve Officers' Training Corps", "Republic Officers' Training Committee", "Regional Officers' Training Corps", "Reserve Organization Training Committee"], answer: 0, explanation: "ROTC = Reserve Officers' Training Corps — the military-oriented NSTP component for national defense training." },
  { question: "LTS stands for:", options: ["Leadership and Training Service", "Literacy Training Service", "Local Training System", "Law and Training Service"], answer: 1, explanation: "LTS = Literacy Training Service — focuses on teaching literacy and numeracy skills in communities." },
  { question: "The primary focus of CWTS is:", options: ["Military defense training", "Community service, civic consciousness, and social development", "Teaching mathematics only", "Government administration training"], answer: 1, explanation: "CWTS focuses on activities that enhance civic consciousness and contribute to the betterment and welfare of the community." },
  { question: "NSTP units required for graduation:", options: ["3 units (NSTP 1 only)", "6 units (NSTP 1 and NSTP 2)", "9 units (3 semesters)", "12 units (4 semesters)"], answer: 1, explanation: "Students must complete NSTP 1 and NSTP 2 (3 units each) for a total of 6 units as a requirement for graduation." },
  { question: "CWTS class hours per week are:", options: ["1 hour per week", "2 hours per week", "3 hours per week", "5 hours per week"], answer: 2, explanation: "CWTS runs for 3 hours per week for 2 semesters (NSTP 1 and NSTP 2)." },
  { question: "The NSTP component that focuses on teaching literacy and numeracy in communities is:", options: ["CWTS", "ROTC", "LTS", "CMT"], answer: 2, explanation: "LTS (Literacy Training Service) trains students to teach literacy and numeracy skills to less privileged communities." },
  { question: "The Disaster Risk Reduction and Management Act is:", options: ["RA 9163", "RA 10121", "RA 10175", "RA 10173"], answer: 1, explanation: "RA 10121 (2010) is the Philippine Disaster Risk Reduction and Management Act — it established the comprehensive national DRRM framework." },
  { question: "RA 10121 created which national government body?", options: ["PAGASA", "PHIVOLCS", "NDRRMC", "OCD"], answer: 2, explanation: "RA 10121 created the NDRRMC (National Disaster Risk Reduction and Management Council) as the highest policy-making body for DRRM in the Philippines." },
  { question: "NDRRMC stands for:", options: ["National Defense Rescue and Relief Management Council", "National Disaster Risk Reduction and Management Council", "National Development Resource and Recovery Management Committee", "National Department of Risk Reduction and Management Council"], answer: 1, explanation: "NDRRMC = National Disaster Risk Reduction and Management Council — created by RA 10121 to coordinate disaster risk reduction efforts." },
  { question: "Disaster Risk Reduction (DRR) is defined as:", options: ["Responding only after disasters occur", "Systematic efforts to reduce disaster risks through reducing hazard exposure, vulnerability, and improving preparedness", "Giving aid to victims only", "Building stronger houses"], answer: 1, explanation: "DRR involves systematic efforts including reduced exposure to hazards, lessened vulnerability of people and property, and improved preparedness." },
  { question: "Which is the FIRST phase of the DRRM cycle?", options: ["Response", "Recovery and Rehabilitation", "Prevention and Mitigation", "Preparedness"], answer: 2, explanation: "The four DRRM phases are: 1. Prevention and Mitigation, 2. Preparedness, 3. Response, 4. Recovery and Rehabilitation." },
  { question: "The Preparedness phase of DRRM involves:", options: ["Rebuilding infrastructure after disaster", "Training, drills, emergency plans, and stockpiling before a disaster", "Search and rescue during disaster", "Only government budgeting"], answer: 1, explanation: "Preparedness includes activities done before a disaster strikes: training, emergency drills, developing response plans, and stockpiling emergency supplies." },
  { question: "The Response phase of DRRM refers to:", options: ["Land use planning and building codes", "Long-term livelihood restoration", "Search and rescue, evacuation, and emergency relief during and immediately after a disaster", "Conducting community risk assessments"], answer: 2, explanation: "Response = immediate actions during and after disaster: search and rescue, evacuation, emergency medical care, and relief distribution." },
  { question: "Recovery and Rehabilitation in DRRM includes:", options: ["Preventing disasters from happening", "Rebuilding infrastructure, restoring livelihoods, and providing psychosocial support", "Only search and rescue operations", "Only government policy-making"], answer: 1, explanation: "Recovery and Rehabilitation: long-term rebuilding phase — restoring infrastructure, livelihoods, and community well-being after a disaster." },
  { question: "An average of how many typhoons hit the Philippines per year?", options: ["5", "10", "20", "50"], answer: 2, explanation: "The Philippines experiences an average of about 20 typhoons per year due to its location in the Pacific typhoon belt." },
  { question: "The Philippines is located on which geological feature that makes it prone to earthquakes?", options: ["Amazon Basin", "Pacific Ring of Fire", "Atlantic Ridge", "Indian Tectonic Shelf"], answer: 1, explanation: "The Philippines lies on the Pacific Ring of Fire — a belt of high seismic and volcanic activity surrounding the Pacific Ocean." },
  { question: "The Valley Fault System is a major earthquake risk located near:", options: ["Cebu City", "Davao City", "Metro Manila", "Iloilo City"], answer: 2, explanation: "The West and East Valley Fault Systems run through Metro Manila and its surrounding provinces, posing a major earthquake risk to the capital region." },
  { question: "How many active volcanoes does the Philippines have?", options: ["5", "14", "24", "45"], answer: 2, explanation: "The Philippines has 24 active volcanoes, including Mayon, Pinatubo, and Taal — reflecting its position on the Ring of Fire." },
  { question: "Taal Volcano's most recent major eruption was in:", options: ["1991", "2004", "2013", "2020"], answer: 3, explanation: "Taal Volcano erupted in January 2020, releasing ash and lava fountains — its most significant eruption in decades." },
  { question: "The strongest Philippine typhoon on record is:", options: ["Typhoon Ondoy", "Typhoon Frank", "Typhoon Yolanda (Hainan)", "Typhoon Pablo"], answer: 2, explanation: "Super Typhoon Yolanda (international name: Haiyan) struck in November 2013 and is considered the strongest typhoon to make landfall in recorded history." },
  { question: "Landslides in the Philippines are most likely to occur:", options: ["Only in Metro Manila", "In mountainous provinces during or after heavy rains", "Only during summer", "Only in coastal areas"], answer: 1, explanation: "Landslides are common in the Philippines' mountainous provinces, particularly when heavy rainfall saturates slopes — often triggered by typhoons." },
  { question: "Volunteerism in CWTS is best defined as:", options: ["Mandatory paid work for the government", "Freely giving time, skills, and effort for community benefit without expectation of financial reward", "Only physical labor for private companies", "Joining the military reserve"], answer: 1, explanation: "Volunteerism = freely giving time, talent, and effort to serve others and benefit the community — a core value in CWTS." },
  { question: "Which Filipino value means 'shared identity' — recognizing others as part of your community?", options: ["Bayanihan", "Kapwa", "Malasakit", "Pagmamahal sa bayan"], answer: 1, explanation: "Kapwa is the Filipino concept of 'shared self' or shared identity — recognizing that others are not separate from you but part of your community." },
  { question: "Bayanihan refers to:", options: ["Individual achievement above all", "Community spirit and collective effort for a common good", "Loyalty to one's family only", "Competition among neighbors"], answer: 1, explanation: "Bayanihan is the Filipino tradition of people working together as a community — embodying collective effort and mutual help." },
  { question: "Malasakit means:", options: ["Pride in personal achievement", "Compassion and genuine concern for the welfare of others", "Strict discipline in following rules", "Competitive success in business"], answer: 1, explanation: "Malasakit is a Filipino value expressing compassion, empathy, and caring concern for others — particularly for those in need." },
  { question: "Pagmamahal sa bayan means:", options: ["Loyalty to one's family only", "Love of country and patriotism", "Respect for elders only", "Personal ambition for success"], answer: 1, explanation: "Pagmamahal sa bayan = love of country (patriotism) — one of the core Filipino values promoted in CWTS and community service." },
  { question: "Community development is best defined as:", options: ["A government program that builds only roads", "A process through which communities organize and improve their own social and economic well-being", "Individual efforts by one person to solve community problems", "An emergency relief operation only"], answer: 1, explanation: "Community development involves the organized efforts of community members to improve their collective social, economic, and cultural conditions." },
  { question: "The first step in community assessment is:", options: ["Immediately implementing a project", "Identifying community needs and problems through surveys and interviews", "Building facilities", "Distributing supplies"], answer: 1, explanation: "Community assessment begins by identifying what the community needs — using methods like surveys, interviews, and focus group discussions." },
  { question: "SMART in SMART objectives stands for:", options: ["Simple, Meaningful, Accurate, Realistic, Timely", "Specific, Measurable, Achievable, Relevant, Time-bound", "Specific, Manageable, Accurate, Realistic, Timely", "Simple, Measurable, Achievable, Relevant, Time-bound"], answer: 1, explanation: "SMART = Specific, Measurable, Achievable, Relevant, Time-bound — the standard framework for writing effective project objectives." },
  { question: "An example of a SMART objective is:", options: ["'Help the community'", "'Reduce littering by 50% in Barangay X within 3 months through weekly clean-up drives'", "'Do something good for people'", "'Be helpful whenever possible'"], answer: 1, explanation: "A SMART objective is Specific (reduce littering), Measurable (50%), Achievable, Relevant, and Time-bound (3 months) — unlike vague goals." },
  { question: "Peace education is defined as:", options: ["Physical training for military defense", "The process of acquiring values, knowledge, and skills that promote nonviolent coexistence and conflict resolution", "Learning only about foreign wars", "Discipline enforcement in schools"], answer: 1, explanation: "Peace education teaches values, knowledge, and skills that promote peaceful coexistence, nonviolence, conflict resolution, and social justice." },
  { question: "Which DRRM phase includes early warning systems and risk assessment?", options: ["Response", "Recovery and Rehabilitation", "Prevention and Mitigation", "Preparedness"], answer: 2, explanation: "Prevention and Mitigation focuses on reducing disaster risks BEFORE they occur — including risk assessment, early warning systems, and land use planning." },
  { question: "A technological/human-induced disaster is caused by:", options: ["Natural earth processes", "Human actions, errors, or failures of manufactured systems", "Only government neglect", "Weather patterns alone"], answer: 1, explanation: "Technological disasters include oil spills, chemical releases, bioterrorism, and radiation emergencies — caused by human activities or failures." },
  { question: "A complex emergency is characterized by:", options: ["Only natural weather events", "Disrupted livelihoods and threats to life from warfare or civil disturbance in difficult political/security environments", "Only single-agency situations", "Only urban flooding"], answer: 1, explanation: "Complex emergencies arise from armed conflict or civil disturbance — creating large-scale humanitarian crises requiring multi-agency international response." },
  { question: "Which Philippine province is particularly known for volcanic risk due to Mayon Volcano?", options: ["Ilocos Norte", "Albay (Bicol Region)", "Mountain Province", "Palawan"], answer: 1, explanation: "Mayon Volcano — the world's most perfect cone — is located in Albay province in the Bicol Region and is one of the most active Philippine volcanoes." },
  { question: "Project monitoring in community service refers to:", options: ["Writing the final report only", "Tracking the project's progress against the plan during implementation and adjusting as needed", "Only distributing supplies", "Evaluating outcomes after the project ends"], answer: 1, explanation: "Monitoring is ongoing — it tracks whether activities are being implemented as planned and allows for adjustments during the project." },
  { question: "Project evaluation in community service refers to:", options: ["The same as monitoring", "Measuring outcomes after the project — did it achieve its objectives?", "Only counting materials used", "Only documenting expenses"], answer: 1, explanation: "Evaluation assesses outcomes and impact at the end of a project — measuring whether objectives were met and what effects were produced." },
  { question: "Service learning combines community service with:", options: ["Military training", "Academic study and structured reflection on the service experience", "Only physical labor", "Passive observation of community life"], answer: 1, explanation: "Service learning integrates meaningful community service with academic learning and guided reflection — connecting classroom content to real community issues." },
  { question: "The Philippines' archipelagic geography (over 7,100 islands) increases its vulnerability to:", options: ["Only droughts", "Storm surges, tsunamis, coastal flooding, and typhoons", "Only volcanic eruptions", "Only earthquakes"], answer: 1, explanation: "An archipelago nation with extensive coastlines is especially vulnerable to storm surges, sea-level rise, coastal flooding, and typhoon-related hazards." },
  { question: "A focus group discussion (FGD) in community assessment is used to:", options: ["Interview only government officials", "Gather in-depth opinions and insights from community members about their needs and issues", "Conduct physical skills training", "Distribute emergency supplies"], answer: 1, explanation: "FGDs bring together small groups of community members to discuss their needs, experiences, and perspectives — providing richer qualitative data than surveys alone." },
  { question: "According to RA 9163, students may choose any of the 3 NSTP components based on:", options: ["Only their professor's assignment", "Their own preference, with the component determined by the school's offerings and student choice", "The government's mandatory assignment", "Random selection by the school"], answer: 1, explanation: "RA 9163 allows students to choose which NSTP component they wish to take, subject to what the school offers." },
  { question: "The CWTS program philosophy is best summarized as:", options: ["Physical strength and military discipline above all", "Civic awareness, volunteerism, and service to the community for national development", "Personal career advancement through community projects", "Only academic knowledge application"], answer: 1, explanation: "CWTS aims to develop civic-consciousness and defense preparedness through community service and voluntary activities for national development." },
  { question: "The Mt. Pinatubo eruption in the Philippines occurred in:", options: ["1981", "1991", "2001", "2011"], answer: 1, explanation: "Mt. Pinatubo erupted in June 1991 — one of the largest volcanic eruptions of the 20th century — displacing hundreds of thousands and causing widespread destruction." },
  { question: "Which DRRM approach focuses on reducing the underlying causes of disaster risk rather than just responding to disasters?", options: ["Pure emergency response", "Disaster Risk Reduction (proactive mitigation and prevention)", "Only post-disaster reconstruction", "Only evacuation planning"], answer: 1, explanation: "DRR takes a proactive approach — addressing root causes of vulnerability, hazard exposure, and poor preparedness, rather than only responding after disasters occur." },
];

