        sections: [
          { type: "definition", content: "Form — how the artwork is created: the visual organization and arrangement of elements, principles, and medium." },
          { type: "table", content: "Seven Elements of Art", headers: ["Element", "Meaning", "Exam Clue"], rows: [["Line", "A mark made by a moving point; straight, curved, thick, thin, or implied.", "Defines shapes, creates patterns, suggests movement."], ["Shape", "A two-dimensional area defined by lines or other elements.", "Geometric shapes: circles, squares, triangles; organic shapes: irregular/natural forms."], ["Form", "Three-dimensional quality with height, width, and depth.", "Cubes, spheres, cylinders, sculptures, realistic painted volume."], ["Space", "Area within, around, and between objects.", "Positive space = occupied area; negative space = empty area around objects."], ["Texture", "Surface quality, real or implied.", "Rough stone, smooth glass, soft cloth, bumpy surface."], ["Value", "Lightness or darkness of a color or tone.", "Creates contrast, mood, depth, and volume."], ["Color", "Visual perception of reflected light.", "Hue = color name; value = light/dark; intensity = purity/saturation."]] },
          { type: "note", content: "Elements are the building blocks. Artists use them as visual tools to express ideas." },
        ],
        quiz: [
          { question: "Which element creates the illusion of depth through lightness and darkness?", options: ["Value", "Curator", "Canon", "Patron"], answer: 0, explanation: "Value is the gradation of light and dark." },
          { question: "Which pair is correct?", options: ["Positive space—occupied area; negative space—empty area", "Positive space—cash benefit; negative space—museum", "Texture—only price", "Color—only line thickness"], answer: 0, explanation: "Space deals with occupied and empty areas in composition." },
          { question: "Hue means:", options: ["The name of the color", "The owner of the art", "The buyer's role", "A dance award"], answer: 0, explanation: "Hue is the color name such as red, blue, or yellow." },
        ],
