        module: "Module 4: Work of Arts — Subject, Form, and Content",
        objectives: ["Identify the principles of art and design", "Explain how medium shapes art experience", "Use examples to recognize balance, contrast, emphasis, movement, rhythm, unity, and variety"],
        sections: [
          { type: "definition", content: "Principles of Art — rules or guidelines that govern how artists organize the elements of art to create effective compositions." },
          { type: "table", content: "Principles of Art and Design", headers: ["Principle", "Meaning", "Examples / Clues"], rows: [["Balance", "Distribution of visual weight; a composition feels stable.", "Symmetrical balance is even; asymmetrical balance uses unequal but visually stable parts; Botticelli's The Birth of Venus."], ["Contrast", "Grouping opposite/different elements to highlight differences.", "Light vs dark, rough vs smooth, large vs small; Caravaggio's The Calling of Saint Matthew."], ["Emphasis", "Creates focal point or dominant area.", "Draws attention through contrast, placement, size, color; Vermeer's Girl with a Pearl Earring."], ["Movement", "Guides the viewer's eye through the artwork.", "Diagonal/curvy lines, repetition, energetic marks; Hokusai's The Great Wave; Van Gogh's Starry Night."], ["Pattern", "Regular repetition of visual elements.", "Geometric or organic repetition; M.C. Escher's Day and Night."], ["Rhythm", "Repetition with flow or beat that leads the eye.", "Regular rhythm, flowing rhythm, random rhythm; Mondrian and Pollock examples."], ["Unity", "Cohesiveness and completeness; parts belong together.", "Picasso's Guernica feels unified through shared mood, forms, and theme."], ["Variety", "Introduces visual interest and prevents monotony.", "Bosch's The Garden of Earthly Delights shows many varied forms; too much variety can be overwhelming."]] },
          { type: "definition", content: "Medium — the material or tool used to create an artwork. Examples: oil paint, watercolor, acrylic, clay, marble, bronze, metal, film photography, digital photography, mixed media, and digital tools." },
          { type: "list", content: "Medium examples from the module:", items: ["Painting: oil gives depth and blending; watercolor gives transparency and delicacy; acrylic offers flexible modern use.", "Sculpture: clay, marble, bronze, or metal emphasizes three-dimensional form and space; Michelangelo's David demonstrates marble's power in representing anatomy.", "Photography: captures moments with precision and can manipulate light, shadow, and composition.", "Mixed media/digital art: combines traditional and modern tools for contemporary experimentation."] },
        ],
        quiz: [
          { question: "Which principle creates a focal point?", options: ["Emphasis", "Texture", "Hue", "Medium"], answer: 0, explanation: "Emphasis draws attention to a particular element or area." },
          { question: "Rhythm is best described as:", options: ["Repetition creating flow and movement", "The color name", "The price of artwork", "A government benefit"], answer: 0, explanation: "Rhythm repeats elements in a way that guides the eye." },
          { question: "Which is a medium?", options: ["Oil paint", "Balance", "Subjective content", "Art buyer"], answer: 0, explanation: "Oil paint is a material used to create an artwork." },
        ],
